// AUTO-GENERATED — the single theme-preset library. Each entry is a COMPLETE
// look (colors + fonts + radius + shadow scale) the design agent picks by
// description and the human picks in the tweaker. `category` groups presets by
// visual style (Minimal · Soft · Bold · Editorial · Brutalism · Neumorphism ·
// Claymorphism). Domain presets fold in the former design/presets/*.DESIGN.md;
// the rest are tweakcn palettes. Shadow tokens (shadow-2xs … shadow-2xl) ride in
// the light/dark maps and are emitted as CSS vars by the runtime.
// Regenerate via scripts/_add-shadows.ts.

export interface ThemePreset {
  id: string;
  label: string;
  /** One-line character note (palette · mood · good-for) — the pick signal. */
  description: string;
  /** Visual style family — groups the picker. */
  category: string;
  /** Tile swatch — the light-mode primary. */
  swatch: string;
  radius: string;
  /** Google Font pairing (families from lib/jr/theme-options). */
  fonts: { heading: string; body: string };
  /** shadcn token name (kebab) -> value, light palette (incl. shadow-* scale). */
  light: Record<string, string>;
  /** shadcn token name (kebab) -> value, dark palette (incl. shadow-* scale). */
  dark: Record<string, string>;
}

